# ============================================================
# Step 1: Validate Cart Items
# ============================================================
def validate_cart(cart_items: list[CartItem], user: User) -> ValidatedCart:
    """
    Step 1: Validate all cart items.
    - Check items are not empty
    - Check each item is available
    - Check quantities are valid
    - Check prices are positive
    - Calculate subtotal
    """
    if not cart_items:
        raise CartValidationError("Cart is empty.", {"user_id": user.user_id})

    validated_items = []
    warnings = []
    subtotal = 0.0
    total_item_count = 0

    seen_item_ids = set()

    for item in cart_items:
        # Check for duplicate items
        if item.item_id in seen_item_ids:
            raise CartValidationError(
                f"Duplicate item in cart: {item.name} (ID: {item.item_id})",
                {"item_id": item.item_id}
            )
        seen_item_ids.add(item.item_id)

        # Check availability
        if not item.is_available:
            raise CartValidationError(
                f"Item '{item.name}' (ID: {item.item_id}) is not available.",
                {"item_id": item.item_id, "item_name": item.name}
            )

        # Check quantity
        if item.quantity <= 0:
            raise CartValidationError(
                f"Invalid quantity ({item.quantity}) for item '{item.name}'.",
                {"item_id": item.item_id, "quantity": item.quantity}
            )

        if item.quantity > item.max_quantity:
            raise CartValidationError(
                f"Quantity ({item.quantity}) exceeds maximum ({item.max_quantity}) for item '{item.name}'.",
                {"item_id": item.item_id, "quantity": item.quantity, "max_quantity": item.max_quantity}
            )

        # Warn if quantity is high
        if item.quantity > item.max_quantity * 0.8:
            warnings.append(
                f"Item '{item.name}' quantity ({item.quantity}) is near the maximum limit ({item.max_quantity})."
            )

        # Check price
        if item.price < 0:
            raise CartValidationError(
                f"Invalid price ({item.price}) for item '{item.name}'.",
                {"item_id": item.item_id, "price": item.price}
            )

        if item.price == 0:
            warnings.append(f"Item '{item.name}' has a price of $0.00.")

        item_total = round(item.price * item.quantity, 2)
        subtotal += item_total
        total_item_count += item.quantity
        validated_items.append(item)

    subtotal = round(subtotal, 2)

    print(f"  [Step 1] Cart validated: {len(validated_items)} unique items, "
          f"{total_item_count} total units, subtotal=${subtotal:.2f}")
    if warnings:
        for w in warnings:
            print(f"  [Step 1] WARNING: {w}")

    return ValidatedCart(
        items=validated_items,
        subtotal=subtotal,
        item_count=total_item_count,
        warnings=warnings,
    )


# ============================================================
# Step 2: Apply Discount Codes
# ============================================================
def validate_user_discount_permission(user: User, discount: DiscountCode) -> tuple[bool, str]:
    """Check if a user has permission to use a specific discount code."""
    # Check if code is active
    if not discount.is_active:
        return False, f"Discount code '{discount.code}' is no longer active."

    # Check usage limits
    if discount.max_uses != -1 and discount.current_uses >= discount.max_uses:
        return False, f"Discount code '{discount.code}' has reached its maximum usage limit."

    # Check admin-only
    if discount.admin_only and not user.is_admin:
        return False, f"Discount code '{discount.code}' is restricted to admin users only."

    # Check tier permission
    if user.tier not in discount.allowed_tiers:
        return False, (
            f"Discount code '{discount.code}' is not available for {user.tier.value} tier users. "
            f"Required tiers: {[t.value for t in discount.allowed_tiers]}"
        )

    return True, "Permission granted."


def apply_discount_codes(
    validated_cart: ValidatedCart,
    discount_codes: list[str],
    user: User
) -> DiscountResult:
    """
    Step 2: Apply discount codes.
    Depends on Step 1 output (ValidatedCart).
    - Look up codes in DB
    - Validate user permissions for each code
    - Check minimum order amounts
    - Handle stackable vs non-stackable codes
    - Calculate discount amount
    """
    applied_codes = []
    rejected_codes = []
    total_discount_percentage = 0.0
    has_non_stackable = False

    if not discount_codes:
        print(f"  [Step 2] No discount codes provided. Subtotal remains ${validated_cart.subtotal:.2f}")
        return DiscountResult(
            validated_cart=validated_cart,
            applied_codes=[],
            total_discount_amount=0.0,
            subtotal_after_discount=validated_cart.subtotal,
            rejected_codes=[],
        )

    for code_str in discount_codes:
        code_str = code_str.strip().upper()

        # Look up code
        discount = DISCOUNT_CODES_DB.get(code_str)
        if discount is None:
            rejected_codes.append({"code": code_str, "reason": "Code not found."})
            print(f"  [Step 2] Code '{code_str}' not found - rejected.")
            continue

        # Validate user permission
        permitted, permission_msg = validate_user_discount_permission(user, discount)
        if not permitted:
            rejected_codes.append({"code": code_str, "reason": permission_msg})
            print(f"  [Step 2] Code '{code_str}' permission denied: {permission_msg}")
            continue

        # Check minimum order amount
        if validated_cart.subtotal < discount.min_order_amount:
            reason = (
                f"Minimum order amount of ${discount.min_order_amount:.2f} not met. "
                f"Current subtotal: ${validated_cart.subtotal:.2f}"
            )
            rejected_codes.append({"code": code_str, "reason": reason})
            print(f"  [Step 2] Code '{code_str}' rejected: {reason}")
            continue

        # Check stackability
        if has_non_stackable:
            reason = "A non-stackable discount code has already been applied."
            rejected_codes.append({"code": code_str, "reason": reason})
            print(f"  [Step 2] Code '{code_str}' rejected: {reason}")
            continue

        if not discount.stackable:
            if applied_codes:
                reason = (
                    f"Code '{code_str}' is non-stackable and cannot be combined with other codes."
                )
                rejected_codes.append({"code": code_str, "reason": reason})
                print(f"  [Step 2] Code '{code_str}' rejected: {reason}")
                continue
            has_non_stackable = True

        # Apply the code
        total_discount_percentage += discount.discount_percentage
        applied_codes.append({
            "code": discount.code,
            "discount_percentage": discount.discount_percentage,
        })
        print(f"  [Step 2] Code '{discount.code}' applied: {discount.discount_percentage}% off")

    # Cap total discount at 100%
    if total_discount_percentage > 100.0:
        total_discount_percentage = 100.0
        print(f"  [Step 2] Total discount capped at 100%")

    total_discount_amount = round(validated_cart.subtotal * (total_discount_percentage / 100.0), 2)
    subtotal_after_discount = round(validated_cart.subtotal - total_discount_amount, 2)

    print(f"  [Step 2] Total discount: {total_discount_percentage}% = -${total_discount_amount:.2f}")
    print(f"  [Step 2] Subtotal after discount: ${subtotal_after_discount:.2f}")

    return DiscountResult(
        validated_cart=validated_cart,
        applied_codes=applied_codes,
        total_discount_amount=total_discount_amount,
        subtotal_after_discount=subtotal_after_discount,
        rejected_codes=rejected_codes,
    )


# ============================================================
# Step 3: Calculate Tax
# ============================================================
def calculate_tax(
    discount_result: DiscountResult,
    state: str,
    item_categories: dict[str, str] = None
) -> TaxResult:
    """
    Step 3: Calculate tax based on state and item categories.
    Depends on Step 2 output (DiscountResult).
    - Look up tax rate by state
    - Apply additional category-based taxes
    - Calculate total with tax
    """
    item_categories = item_categories or {}

    tax_config = TAX_CONFIGS.get(state.upper())
    if tax_config is None:
        raise TaxCalculationError(
            f"Tax configuration not found for state '{state}'.",
            {"state": state, "available_states": list(TAX_CONFIGS.keys())}
        )

    base_amount = discount_result.subtotal_after_discount
    base_tax = round(base_amount * tax_config.tax_rate, 2)

    tax_breakdown = {
        "state": state.upper(),
        "base_rate": tax_config.tax_rate,
        "base_tax": base_tax,
        "category_taxes": {},
    }

    # Calculate additional category-based taxes on individual items
    additional_tax = 0.0
    for item in discount_result.validated_cart.items:
        category = item_categories.get(item.item_id, "general")
        if category in tax_config.additional_rates:
            # Apply the discount proportion to this item's amount
            item_total = item.price * item.quantity
            if discount_result.validated_cart.subtotal > 0:
                discount_proportion = discount_result.subtotal_after_discount / discount_result.validated_cart.subtotal
            else:
                discount_proportion = 1.0
            item_discounted = round(item_total * discount_proportion, 2)
            cat_tax = round(item_discounted * tax_config.additional_rates[category], 2)
            additional_tax += cat_tax

            if category not in tax_breakdown["category_taxes"]:
                tax_breakdown["category_taxes"][category] = {
                    "rate": tax_config.additional_rates[category],
                    "amount": 0.0,
                    "items": [],
                }
            tax_breakdown["category_taxes"][category]["amount"] += cat_tax
            tax_breakdown["category_taxes"][category]["items"].append(item.name)

    additional_tax = round(additional_tax, 2)
    total_tax = round(base_tax + additional_tax, 2)
    total_with_tax = round(base_amount + total_tax, 2)

    tax_breakdown["additional_tax"] = additional_tax
    tax_breakdown["total_tax"] = total_tax

    print(f"  [Step 3] State: {state.upper()}, Base tax rate: {tax_config.tax_rate * 100:.2f}%")
    print(f"  [Step 3] Base tax: ${base_tax:.2f}, Additional category tax: ${additional_tax:.2f}")
    print(f"  [Step 3] Total tax: ${total_tax:.2f}")
    print(f"  [Step 3] Total with tax: ${total_with_tax:.2f}")

    return TaxResult(
        discount_result=discount_result,
        tax_amount=total_tax,
        tax_breakdown=tax_breakdown,
        total_with_tax=total_with_tax,
    )


# ============================================================
# Step 4: Process Payment
# ============================================================
def process_payment(
    tax_result: TaxResult,
    payment_info: PaymentInfo
) -> PaymentResult:
    """
    Step 4: Process the payment.
    Depends on Step 3 output (TaxResult).
    - Validate payment info
    - Simulate payment processing
    - Return transaction result
    """
    amount = tax_result.total_with_tax

    if amount < 0:
        raise PaymentError("Payment amount cannot be negative.", {"amount": amount})

    # If amount is zero (100% discount + no tax), skip payment processing
    if amount == 0:
        transaction_id = f"TXN-FREE-{uuid.uuid4().hex[:12].upper()}"
        print(f"  [Step 4] Order total is $0.00. No payment required. Transaction ID: {transaction_id}")
        return PaymentResult(
            tax_result=tax_result,
            transaction_id=transaction_id,
            payment_status="success",
            amount_charged=0.0,
            payment_method=payment_info.method,
        )

    # Validate payment info based on method
    if payment_info.method in (PaymentMethod.CREDIT_CARD, PaymentMethod.DEBIT_CARD):
        if not payment_info.card_number:
            raise PaymentError("Card number is required.", {"method": payment_info.method.value})
        if not payment_info.expiry:
            raise PaymentError("Card expiry date is required.", {"method": payment_info.method.value})
        if not payment_info.cvv:
            raise PaymentError("CVV is required.", {"method": payment_info.method.value})

        # Basic card number validation (length check)
        clean_card = payment_info.card_number.replace(" ", "").replace("-", "")
        if len(clean_card) < 13 or len(clean_card) > 19:
            raise PaymentError("Invalid card number length.", {"card_length": len(clean_card)})
        if not clean_card.isdigit():
            raise PaymentError("Card number must contain only digits.")

        # CVV validation
        if len(payment_info.cvv) not in (3, 4) or not payment_info.cvv.isdigit():
            raise PaymentError("Invalid CVV format.")

    elif payment_info.method == PaymentMethod.PAYPAL:
        if not payment_info.paypal_email:
            raise PaymentError("PayPal email is required.", {"method": payment_info.method.value})
        if "@" not in payment_info.paypal_email:
            raise PaymentError("Invalid PayPal email format.")

    elif payment_info.method == PaymentMethod.BANK_TRANSFER:
        if not payment_info.bank_account:
            raise PaymentError("Bank account number is required.", {"method": payment_info.method.value})

    # Simulate payment processing
    print(f"  [Step 4] Processing {payment_info.method.value} payment for ${amount:.2f}...")

    if payment_info.method in (PaymentMethod.CREDIT_CARD, PaymentMethod.DEBIT_CARD):
        clean_card = payment_info.card_number.replace(" ", "").replace("-", "")
        sim_result = PAYMENT_SIMULATION.get(clean_card, PAYMENT_SIMULATION["default"])
    else:
        sim_result = "success"

    transaction_id = f"TXN-{uuid.uuid4().hex[:12].upper()}"

    if sim_result == "declined":
        raise PaymentError(
            "Payment declined by the issuing bank.",
            {"transaction_id": transaction_id, "status": "declined"}
        )
    elif sim_result == "expired_card":
        raise PaymentError(
            "Payment failed: card is expired.",
            {"transaction_id": transaction_id, "status": "expired_card"}
        )

    print(f"  [Step 4] Payment successful! Transaction ID: {transaction_id}, Amount: ${amount:.2f}")

    return PaymentResult(
        tax_result=tax_result,
        transaction_id=transaction_id,
        payment_status="success",
        amount_charged=amount,
        payment_method=payment_info.method,
    )


# ============================================================
# Step 5: Create Order Record
# ============================================================
def create_order_record(
    payment_result: PaymentResult,
    user: User
) -> OrderRecord:
    """
    Step 5: Create the final order record.
    Depends on Step 4 output (PaymentResult).
    - Compile all information from previous steps
    - Generate order ID
    - Create immutable order record
    """
    tax_result = payment_result.tax_result
    discount_result = tax_result.discount_result
    validated_cart = discount_result.validated_cart

    order_id = f"ORD-{uuid.uuid4().hex[:12].upper()}"
    created_at = datetime.utcnow().isoformat() + "Z"

    order = OrderRecord(
        order_id=order_id,
        user=user,
        items=[
            {
                "item_id": item.item_id,
                "name": item.name,
                "price": item.price,
                "quantity": item.quantity,
                "line_total": round(item.price * item.quantity, 2),
            }
            for item in validated_cart.items
        ],
        subtotal=validated_cart.subtotal,
        discount_amount=discount_result.total_discount_amount,
        applied_discounts=discount_result.applied_codes,
        tax_amount=tax_result.tax_amount,
        tax_breakdown=tax_result.tax_breakdown,
        total_amount=payment_result.amount_charged,
        payment_transaction_id=payment_result.transaction_id,
        payment_method=payment_result.payment_method,
        payment_status=payment_result.payment_status,
        order_status=OrderStatus.COMPLETED,
        created_at=created_at,
        warnings=validated_cart.warnings,
    )

    print(f"  [Step 5] Order created: {order_id}")
    print(f"  [Step 5] Status: {order.order_status.value}")

    return order


# ============================================================
# Main Checkout Pipeline
# ============================================================
def checkout(
    user: User,
    cart_items: list[CartItem],
    discount_codes: list[str],
    state: str,
    payment_info: PaymentInfo,
    item_categories: dict[str, str] = None
) -> OrderRecord:
    """
    Main checkout pipeline that orchestrates all 5 steps.
    Each step depends on the previous step's output.
    """
    print("=" * 60)
    print(f"CHECKOUT STARTED for user: {user.name} ({user.tier.value})")
    print("=" * 60)

    # Step 1: Validate Cart
    print("\n--- Step 1: Validate Cart Items ---")
    validated_cart = validate_cart(cart_items, user)

    # Step 2: Apply Discounts (depends on Step 1)
    print("\n--- Step 2: Apply Discount Codes ---")
    discount_result = apply_discount_codes(validated_cart, discount_codes, user)

    # Step 3: Calculate Tax (depends on Step 2)
    print("\n--- Step 3: Calculate Tax ---")
    tax_result = calculate_tax(discount_result, state, item_categories)

    # Step 4: Process Payment (depends on Step 3)
    print("\n--- Step 4: Process Payment ---")
    payment_result = process_payment(tax_result, payment_info)

    # Step 5: Create Order Record (depends on Step 4)
    print("\n--- Step 5: Create Order Record ---")
    order = create_order_record(payment_result, user)

    print("\n" + "=" * 60)
    print("CHECKOUT COMPLETED SUCCESSFULLY")
    print("=" * 60)

    return order


def print_order_summary(order: OrderRecord):
    """Pretty-print an order summary."""
    print("\n" + "+" * 60)
    print(f"  ORDER SUMMARY")
    print("+" * 60)
    print(f"  Order ID:    {order.order_id}")
    print(f"  Customer:    {order.user.name} ({order.user.email})")
    print(f"  Tier:        {order.user.tier.value}")
    print(f"  Date:        {order.created_at}")
    print(f"  Status:      {order.order_status.value}")
    print("-" * 60)
    print("  ITEMS:")
    for item in order.items:
        print(f"    {item['name']:<30} x{item['quantity']:>3}  ${item['line_total']:>10.2f}")
    print("-" * 60)
    print(f"  {'Subtotal:':<40} ${order.subtotal:>10.2f}")
    if order.discount_amount > 0:
        codes_str = ", ".join(d["code"] for d in order.applied_discounts)
        print(f"  {'Discount (' + codes_str + '):':<40} -${order.discount_amount:>9.2f}")
    print(f"  {'Tax (' + order.tax_breakdown['state'] + '):':<40} ${order.tax_amount:>10.2f}")
    print("=" * 60)
    print(f"  {'TOTAL:':<40} ${order.total_amount:>10.2f}")
    print("=" * 60)
    print(f"  Payment:     {order.payment_method.value} ({order.payment_status})")
    print(f"  Transaction: {order.payment_transaction_id}")
    if order.warnings:
        print("-" * 60)
        print("  WARNINGS:")
        for w in order.warnings:
            print(f"    ⚠ {w}")
    print("+" * 60)


